// src/pages/PreviewPage.js
import React, { useState, useEffect, useRef, useCallback } from "react";
import "./PreviewPage.css";
import { registerUser, loginUser, loginWithGoogle } from "../utils/firebase";

// ── CLARIO LOGO ICON ──
function ClarioIcon({ size = 36 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <linearGradient id="prev-g" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="#b8aefc" />
          <stop offset="100%" stopColor="#6b5cff" />
        </linearGradient>
      </defs>
      <path d="M34 13.5C30.8 10.2 26.6 8 22 8C13.2 8 6 15.2 6 24C6 32.8 13.2 40 22 40C26.6 40 30.8 37.8 34 34.5"
        stroke="url(#prev-g)" strokeWidth="5" strokeLinecap="round" fill="none" />
      <path d="M38 14 L39.4 18 L43.5 19 L39.4 20 L38 24 L36.6 20 L32.5 19 L36.6 18 Z" fill="url(#prev-g)" />
    </svg>
  );
}

// ── ANIMATED COUNTER ──
function AnimatedCounter({ target, suffix = "", duration = 2000 }) {
  const [count, setCount] = useState(0);
  const ref = useRef(null);
  const started = useRef(false);

  useEffect(() => {
    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting && !started.current) {
        started.current = true;
        const start = Date.now();
        const tick = () => {
          const elapsed = Date.now() - start;
          const progress = Math.min(elapsed / duration, 1);
          const eased = 1 - Math.pow(1 - progress, 3);
          setCount(Math.floor(eased * target));
          if (progress < 1) requestAnimationFrame(tick);
        };
        requestAnimationFrame(tick);
      }
    }, { threshold: 0.5 });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, [target, duration]);

  return <span ref={ref}>{count.toLocaleString()}{suffix}</span>;
}

// ── DATA ──
const FEATURES = [
  { icon: "🎙️", title: "Record & Transcribe",  desc: "Speak naturally — Whisper converts your voice to accurate text in seconds.",    color: "#6b5cff", tag: "Core" },
  { icon: "📊", title: "Real-Time Metrics",     desc: "See WPM, filler count, flow, and clarity in one clean dashboard.",              color: "#22c55e", tag: "Analytics" },
  { icon: "🤖", title: "AI Coaching",           desc: "Get personalized feedback from Claude AI with actionable steps each session.",   color: "#f59e0b", tag: "AI-Powered" },
  { icon: "📈", title: "Track Progress",        desc: "Every session is saved. Watch your scores improve with detailed trend charts.",  color: "#f43f5e", tag: "Progress" },
  { icon: "🎯", title: "Practice Scenarios",    desc: "Thesis Defense, Job Interview, Recitation, or General Speaking — your choice.", color: "#06b6d4", tag: "Scenarios" },
  { icon: "🗣️", title: "Pronunciation Coach",  desc: "AI flags mispronounced words and shows you the correct form with examples.",    color: "#a855f7", tag: "Pronunciation" },
];

const SCENARIOS = [
  { emoji: "🎓", label: "Thesis Defense",   color: "#6b5cff" },
  { emoji: "💼", label: "Job Interview",    color: "#22c55e" },
  { emoji: "📖", label: "Recitation",       color: "#f59e0b" },
  { emoji: "🎤", label: "General Speaking", color: "#f43f5e" },
];

const TESTIMONIALS = [
  { name: "Sofia Reyes",     role: "BS Computer Science, CMU",   avatar: "SR", text: "CLARIO helped me cut my filler words from 40 to just 3 in two weeks. My thesis defense went way smoother than expected!", score: 92, color: "#6b5cff" },
  { name: "Marco Dela Cruz", role: "Job Seeker, Fresh Graduate", avatar: "MD", text: "I used to say 'um' every 5 seconds. After 10 sessions on CLARIO, I landed my first job — feedback said 'very articulate.'", score: 87, color: "#22c55e" },
  { name: "Janna Okit",      role: "Public Speaking Class, CMU", avatar: "JO", text: "The AI feedback is incredibly specific — it told me exactly which words I mispronounced and how to fix them.", score: 95, color: "#f59e0b" },
];

// ── AUTH MODAL ──
function AuthModal({ initialMode, onClose, onAuth }) {
  const [mode, setMode]           = useState(initialMode || "login");
  const [name, setName]           = useState("");
  const [email, setEmail]         = useState("");
  const [password, setPassword]   = useState("");
  const [confirm, setConfirm]     = useState("");
  const [showPass, setShowPass]   = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [error, setError]         = useState("");
  const [loading, setLoading]     = useState(false);
  const [googleLoading, setGoogleLoading] = useState(false);

  useEffect(() => {
    document.body.style.overflow = "hidden";
    return () => { document.body.style.overflow = ""; };
  }, []);

  useEffect(() => {
    const handleKey = (e) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", handleKey);
    return () => window.removeEventListener("keydown", handleKey);
  }, [onClose]);

  const switchMode = (m) => { setMode(m); setError(""); };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    if (mode === "register") {
      if (!name.trim())        return setError("Please enter your name.");
      if (password.length < 6) return setError("Password must be at least 6 characters.");
      if (password !== confirm) return setError("Passwords do not match.");
    }
    setLoading(true);
    try {
      if (mode === "register") await registerUser(name.trim(), email.trim(), password);
      else await loginUser(email.trim(), password);
      if (onAuth) onAuth();
    } catch (err) {
      const msg = err.code || err.message;
      if (msg.includes("email-already-in-use"))   setError("That email is already registered. Try logging in.");
      else if (msg.includes("user-not-found"))    setError("No account found with that email.");
      else if (msg.includes("wrong-password"))    setError("Incorrect password. Please try again.");
      else if (msg.includes("invalid-email"))     setError("Please enter a valid email address.");
      else if (msg.includes("too-many-requests")) setError("Too many attempts. Please wait a moment.");
      else setError("Something went wrong. Please try again.");
    } finally { setLoading(false); }
  };

  const handleGoogle = async () => {
    setError("");
    setGoogleLoading(true);
    try {
      await loginWithGoogle();
      if (onAuth) onAuth();
    } catch (err) {
      const msg = err.code || err.message;
      if (msg.includes("popup-closed"))        setError("Sign-in cancelled. Please try again.");
      else if (msg.includes("popup-blocked"))  setError("Popup blocked — please allow popups and try again.");
      else if (msg.includes("account-exists")) setError("An account exists with this email. Use email/password login.");
      else setError("Google sign-in failed. Please try again.");
    } finally { setGoogleLoading(false); }
  };

  return (
    <div className="am-overlay" onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="am-shell">
        {/* Left panel */}
        <div className="am-left">
          <div className="am-left-logo">
            <ClarioIcon size={34} />
            <div>
              <span className="am-brand-name">CLARIO</span>
              <span className="am-brand-sub">AI SPEECH COACH</span>
            </div>
          </div>
          <div className="am-left-body">
            <h2>Practice smarter.<br />Speak with confidence.</h2>
            <p>Join students who use AI-powered coaching to eliminate filler words, improve pace, and ace every presentation.</p>
            <div className="am-perks">
              {[["🎙️","Real-time speech analysis"],["🤖","Personalized AI coaching"],["📊","Track progress over time"]].map(([icon, text]) => (
                <div className="am-perk" key={text}><span className="am-perk-icon">{icon}</span><span>{text}</span></div>
              ))}
            </div>
          </div>
          <div className="am-left-scenarios">
            {SCENARIOS.map(s => (
              <span key={s.label} className="am-scenario-chip" style={{ "--sc": s.color }}>{s.emoji} {s.label}</span>
            ))}
          </div>
        </div>

        {/* Right form */}
        <div className="am-right">
          <button className="am-close" onClick={onClose} aria-label="Close">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
              <line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>
            </svg>
          </button>
          <div className="am-form-wrap">
            <div className="am-form-header">
              <h3>{mode === "login" ? "Welcome back!" : "Create your account"}</h3>
              <p>{mode === "login" ? "Log in to continue your sessions." : "Start improving your speech — it's free."}</p>
            </div>
            <div className="am-tabs">
              <button className={`am-tab ${mode === "login" ? "active" : ""}`} onClick={() => switchMode("login")}>Log In</button>
              <button className={`am-tab ${mode === "register" ? "active" : ""}`} onClick={() => switchMode("register")}>Register</button>
            </div>
            <form className="am-form" onSubmit={handleSubmit}>
              {mode === "register" && (
                <div className="am-field">
                  <label>Full Name</label>
                  <div className="am-input-wrap">
                    <span className="am-input-icon">👤</span>
                    <input type="text" placeholder="e.g. Maky Aury Okit" value={name} onChange={e => setName(e.target.value)} required />
                  </div>
                </div>
              )}
              <div className="am-field">
                <label>Email Address</label>
                <div className="am-input-wrap">
                  <span className="am-input-icon">✉️</span>
                  <input type="email" placeholder="you@email.com" value={email} onChange={e => setEmail(e.target.value)} required />
                </div>
              </div>
              <div className="am-field">
                <label>Password</label>
                <div className="am-input-wrap">
                  <span className="am-input-icon">🔒</span>
                  <input type={showPass ? "text" : "password"} placeholder={mode === "register" ? "At least 6 characters" : "Your password"} value={password} onChange={e => setPassword(e.target.value)} required />
                  <button type="button" className="am-pass-toggle" onClick={() => setShowPass(v => !v)}>{showPass ? "Hide" : "Show"}</button>
                </div>
              </div>
              {mode === "register" && (
                <div className="am-field">
                  <label>Confirm Password</label>
                  <div className="am-input-wrap">
                    <span className="am-input-icon">🔒</span>
                    <input type={showConfirm ? "text" : "password"} placeholder="Repeat your password" value={confirm} onChange={e => setConfirm(e.target.value)} required />
                    <button type="button" className="am-pass-toggle" onClick={() => setShowConfirm(v => !v)}>{showConfirm ? "Hide" : "Show"}</button>
                  </div>
                </div>
              )}
              {error && <p className="am-error">⚠️ {error}</p>}
              <button className="am-submit" type="submit" disabled={loading || googleLoading}>
                {loading
                  ? <><span className="am-spinner" /> {mode === "register" ? "Creating account…" : "Logging in…"}</>
                  : mode === "register" ? "Create Free Account →" : "Log In →"
                }
              </button>
            </form>
            <div className="am-divider"><span /><p>or</p><span /></div>
            <button className="am-google-btn" onClick={handleGoogle} disabled={loading || googleLoading} type="button">
              {googleLoading ? <><span className="am-spinner am-spinner-dark" /> Signing in…</> : (
                <>
                  <svg width="17" height="17" viewBox="0 0 48 48" fill="none">
                    <path d="M44.5 20H24v8.5h11.8C34.7 33.9 29.9 37 24 37c-7.2 0-13-5.8-13-13s5.8-13 13-13c3.1 0 5.9 1.1 8.1 2.9l6.4-6.4C34.6 5.1 29.6 3 24 3 12.4 3 3 12.4 3 24s9.4 21 21 21c10.5 0 20-7.6 20-21 0-1.3-.2-2.7-.5-4z" fill="#FFC107"/>
                    <path d="M6.3 14.7l7 5.1C15.1 16.1 19.2 13 24 13c3.1 0 5.9 1.1 8.1 2.9l6.4-6.4C34.6 5.1 29.6 3 24 3 16.3 3 9.7 7.9 6.3 14.7z" fill="#FF3D00"/>
                    <path d="M24 45c5.8 0 10.8-1.9 14.8-5.2l-6.8-5.7C29.9 35.9 27.1 37 24 37c-5.8 0-10.7-3.9-12.4-9.3l-7 5.4C7.8 41 15.3 45 24 45z" fill="#4CAF50"/>
                    <path d="M44.5 20H24v8.5h11.8c-.9 2.9-2.8 5.3-5.4 6.9l6.8 5.7C41.4 38.1 44.5 31.6 44.5 24c0-1.3-.2-2.7-.5-4z" fill="#1976D2"/>
                  </svg>
                  Continue with Google
                </>
              )}
            </button>
            <p className="am-switch">
              {mode === "login"
                ? <>Don't have an account? <button onClick={() => switchMode("register")}>Register here</button></>
                : <>Already have an account? <button onClick={() => switchMode("login")}>Log in here</button></>
              }
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── MAIN COMPONENT ──
export default function PreviewPage({ goToAuth }) {
  const [authModal, setAuthModal] = useState(null);
  const [scrolled, setScrolled]   = useState(false);

  const openAuth = useCallback((mode) => setAuthModal(mode), []);
  const closeAuth = useCallback(() => setAuthModal(null), []);
  const handleAuthSuccess = useCallback(() => {
    if (goToAuth) goToAuth("dashboard");
    setAuthModal(null);
  }, [goToAuth]);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <div className="pv-page">

      {/* ── NAVBAR ── */}
      <nav className={`pv-nav ${scrolled ? "scrolled" : ""}`}>
        <div className="pv-nav-logo">
          <ClarioIcon size={30} />
          <div className="pv-nav-brand">
            <span className="pv-nav-name">CLARIO</span>
            <span className="pv-nav-sub">AI SPEECH COACH</span>
          </div>
        </div>
        <div className="pv-nav-links">
          <a href="#features" className="pv-nav-link">Features</a>
          <a href="#how-it-works" className="pv-nav-link">How It Works</a>
          <a href="#testimonials" className="pv-nav-link">Reviews</a>
        </div>
        <div className="pv-nav-actions">
          <button className="pv-btn-ghost" onClick={() => openAuth("login")}>Log In</button>
          <button className="pv-btn-primary" onClick={() => openAuth("register")}>Get Started Free</button>
        </div>
      </nav>

      {/* ── HERO ── */}
      <section className="pv-hero">
        <div className="pv-hero-inner">
          <span className="pv-eyebrow">
            <span className="pv-eyebrow-dot" />
            AI-Powered · Free to Start · No Setup Required
          </span>
          <h1 className="pv-hero-heading">
            Speak Better.<br />
            <span className="pv-heading-accent">Practice Smarter.</span>
          </h1>
          <p className="pv-hero-sub">
            CLARIO analyzes your speech in real-time — measuring pace, filler words, and clarity — then gives you personalized AI coaching so you can speak with confidence every time.
          </p>
          <div className="pv-hero-cta">
            <button className="pv-btn-primary pv-btn-lg" onClick={() => openAuth("register")}>
              🎙️ Start Practicing Free
            </button>
            <button className="pv-btn-ghost pv-btn-lg" onClick={() => openAuth("login")}>
              I already have an account →
            </button>
          </div>
          <div className="pv-hero-chips">
            <span className="pv-chips-label">Practice for:</span>
            {SCENARIOS.map(s => (
              <span key={s.label} className="pv-chip" style={{ "--sc": s.color }}>{s.emoji} {s.label}</span>
            ))}
          </div>
        </div>

        {/* Demo card */}
        <div className="pv-hero-card-wrap">
          <div className="pv-demo-card">
            <div className="pv-demo-header">
              <span className="pv-demo-title">Live Session · Job Interview</span>
              <span className="pv-demo-rec"><span className="pv-demo-dot" />Recording</span>
            </div>
            <div className="pv-demo-waveform">
              {[...Array(32)].map((_, i) => (
                <div key={i} className="pv-wave-bar"
                  style={{ "--h": `${20 + Math.abs(Math.sin(i * 0.6)) * 55}%`, "--d": `${i * 0.06}s` }} />
              ))}
            </div>
            <div className="pv-demo-rings">
              {[{ val: 87, color: "#6b5cff", label: "Score" }, { val: 92, color: "#22c55e", label: "Clarity" }, { val: 78, color: "#f59e0b", label: "Pace" }].map(r => {
                const circ = 2 * Math.PI * 36;
                return (
                  <div className="pv-ring-wrap" key={r.label}>
                    <svg viewBox="0 0 100 100" width="84" height="84">
                      <circle cx="50" cy="50" r="36" fill="none" stroke="#ede9ff" strokeWidth="8" />
                      <circle cx="50" cy="50" r="36" fill="none" stroke={r.color} strokeWidth="8"
                        strokeDasharray={circ} strokeDashoffset={circ - (r.val / 100) * circ}
                        strokeLinecap="round" transform="rotate(-90 50 50)" />
                      <text x="50" y="55" textAnchor="middle" fontSize="17" fontWeight="800" fill={r.color} fontFamily="Nunito,sans-serif">{r.val}</text>
                    </svg>
                    <span className="pv-ring-label" style={{ color: r.color }}>{r.label}</span>
                  </div>
                );
              })}
            </div>
            <div className="pv-demo-stats">
              {[["142","WPM","#6b5cff"],["3","Fillers","#f43f5e"],["1:12","Duration","#22c55e"]].map(([val, key, color]) => (
                <div className="pv-demo-stat" key={key}>
                  <span className="pv-demo-stat-val" style={{ color }}>{val}</span>
                  <span className="pv-demo-stat-key">{key}</span>
                </div>
              ))}
            </div>
            <div className="pv-demo-lock">🤖 AI Feedback ready — <strong>log in to view</strong></div>
          </div>
        </div>
      </section>

      {/* ── STATS ── */}
      <section className="pv-stats">
        {[
          { value: 2400,  suffix: "+", label: "Students Practicing" },
          { value: 18000, suffix: "+", label: "Sessions Completed" },
          { value: 89,    suffix: "%", label: "Avg Score Improvement" },
          { value: 4,     suffix: "",  label: "Practice Scenarios" },
        ].map(({ value, suffix, label }) => (
          <div className="pv-stat" key={label}>
            <span className="pv-stat-val"><AnimatedCounter target={value} suffix={suffix} /></span>
            <span className="pv-stat-label">{label}</span>
          </div>
        ))}
      </section>

      {/* ── FEATURES ── */}
      <section className="pv-features" id="features">
        <div className="pv-section-header">
          <span className="pv-label">Everything you need</span>
          <h2>Features built for real improvement</h2>
          <p>Every tool in CLARIO is designed to give you precise, actionable feedback — not vague encouragement.</p>
        </div>
        <div className="pv-features-grid">
          {FEATURES.map(f => (
            <div className="pv-feature-card" key={f.title}>
              <div className="pv-feature-icon" style={{ background: `${f.color}15` }}><span>{f.icon}</span></div>
              <span className="pv-feature-tag" style={{ color: f.color, background: `${f.color}12`, border: `1px solid ${f.color}22` }}>{f.tag}</span>
              <h3>{f.title}</h3>
              <p>{f.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* ── HOW IT WORKS ── */}
      <section className="pv-how" id="how-it-works">
        <div className="pv-section-header">
          <span className="pv-label">Simple process</span>
          <h2>From recording to feedback in 3 steps</h2>
        </div>
        <div className="pv-how-steps">
          {[
            { step: "01", icon: "🎯", title: "Choose Your Scenario", desc: "Pick from Thesis Defense, Job Interview, Recitation, or General Speaking.", color: "#6b5cff" },
            { step: "02", icon: "🎙️", title: "Record Your Speech",   desc: "Hit record and speak naturally. A live timer tracks your session duration.", color: "#22c55e" },
            { step: "03", icon: "✨", title: "Get AI Feedback",       desc: "Receive your score, metrics, filler breakdown, and personalized AI coaching.", color: "#f59e0b" },
          ].map((s, i) => (
            <div className="pv-how-step" key={s.step}>
              <div className="pv-step-num" style={{ color: s.color, background: `${s.color}10`, border: `1px solid ${s.color}25` }}>{s.step}</div>
              <div className="pv-step-icon" style={{ background: `${s.color}15` }}>{s.icon}</div>
              <h3>{s.title}</h3>
              <p>{s.desc}</p>
              {i < 2 && <div className="pv-step-arrow">→</div>}
            </div>
          ))}
        </div>
      </section>

      {/* ── SAMPLE RESULTS ── */}
      <section className="pv-sample">
        <div className="pv-sample-inner">
          <div className="pv-sample-text">
            <span className="pv-label">See what you'll get</span>
            <h2>Detailed results after every session</h2>
            <p>After each recording, you get a full breakdown — scores, highlighted transcript, pronunciation coaching, and AI feedback all in one place.</p>
