              {[
                "Overall score with pronunciation, pace, fillers & flow sub-scores",
                "Highlighted transcript showing filler words and unclear speech",
                "Word-by-word pronunciation confidence analysis",
                "Personalized AI coaching in 4 structured sections",
                "Session history and trend charts over time",
              ].map((item, i) => (
                <li key={i}><span className="pv-check">✓</span>{item}</li>
              ))}
            </ul>
            <button className="pv-btn-primary" onClick={() => openAuth("register")}>Try it free — no credit card →</button>
          </div>
          <div className="pv-sample-card">
            <div className="pv-sample-card-top">
              <span className="pv-sample-badge">📊 Your Results</span>
              <span className="pv-sample-scenario">💼 Job Interview</span>
            </div>
            <div className="pv-sample-score-row">
              <div className="pv-sample-ring-wrap">
                <svg viewBox="0 0 100 100" width="86" height="86">
                  <circle cx="50" cy="50" r="38" fill="none" stroke="#ede9ff" strokeWidth="9" />
