                    strokeDasharray={2 * Math.PI * 38} strokeDashoffset={2 * Math.PI * 38 * 0.05}
                    strokeLinecap="round" transform="rotate(-90 50 50)" />
                  <text x="50" y="55" textAnchor="middle" fontSize="18" fontWeight="900" fill="#22c55e" fontFamily="Nunito,sans-serif">95</text>
                </svg>
                <span className="pv-sample-ring-label">EXCELLENT</span>
              </div>
              <div className="pv-sample-bars">
                {[{ label: "Pronunciation", val: 95, color: "#22c55e" }, { label: "Speech Pace", val: 80, color: "#6b5cff" }, { label: "Filler Words", val: 100, color: "#22c55e" }, { label: "Flow", val: 100, color: "#22c55e" }].map(b => (
                  <div className="pv-sample-bar" key={b.label}>
                    <div className="pv-sample-bar-top"><span>{b.label}</span><span style={{ color: b.color, fontWeight: 700 }}>{b.val}</span></div>
                    <div className="pv-sample-bar-track"><div className="pv-sample-bar-fill" style={{ width: `${b.val}%`, background: b.color }} /></div>
                  </div>
