            <div className="pv-sample-metrics">
              {[{ val: "24", label: "Total Words" }, { val: "97", label: "WPM" }, { val: "0", label: "Fillers" }, { val: "95%", label: "Clarity" }].map(m => (
                <div className="pv-sample-metric" key={m.label}>
                  <span className="pv-sm-val">{m.val}</span>
                  <span className="pv-sm-key">{m.label}</span>
                </div>
              ))}
            </div>
            <div className="pv-lock-overlay">
              <div className="pv-lock-content">
                <span>🔒</span>
                <p>Full results visible after login</p>
                <button className="pv-btn-primary" onClick={() => openAuth("register")}>Create Free Account</button>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* ── TESTIMONIALS ── */}
      <section className="pv-testimonials" id="testimonials">
        <div className="pv-section-header">
          <span className="pv-label">Real students, real results</span>
          <h2>What our users say</h2>
        </div>
        <div className="pv-tcard-grid">
          {TESTIMONIALS.map(t => (
            <div className="pv-tcard" key={t.name}>
              <div className="pv-tcard-top">
                <div className="pv-tcard-avatar" style={{ background: `${t.color}18`, color: t.color }}>{t.avatar}</div>
                <div className="pv-tcard-info">
                  <div className="pv-tcard-name">{t.name}</div>
                  <div className="pv-tcard-role">{t.role}</div>
                </div>
                <div className="pv-tcard-score" style={{ color: t.color }}>{t.score}<span>/100</span></div>
              </div>
              <p className="pv-tcard-text">"{t.text}"</p>
              <div className="pv-tcard-stars">{"★".repeat(5)}</div>
            </div>
          ))}
        </div>
      </section>

      {/* ── CTA ── */}
      <section className="pv-cta">
        <h2>Ready to speak with confidence?</h2>
        <p>Join students who practice smarter with CLARIO. Free to start — no credit card required.</p>
        <div className="pv-cta-actions">
          <button className="pv-btn-primary pv-btn-lg" onClick={() => openAuth("register")}>🎙️ Create Free Account</button>
          <button className="pv-btn-outline pv-btn-lg" onClick={() => openAuth("login")}>Log In</button>
        </div>
        <div className="pv-cta-chips">
          {SCENARIOS.map(s => (
            <span key={s.label} className="pv-chip" style={{ "--sc": s.color }}>{s.emoji} {s.label}</span>
          ))}
        </div>
      </section>

      {/* ── FOOTER ── */}
      <footer className="pv-footer">
        <div className="pv-footer-logo">
          <ClarioIcon size={26} />
          <div>
            <span className="pv-nav-name">CLARIO</span>
            <span className="pv-nav-sub" style={{ display: "block" }}>AI SPEECH COACH</span>
          </div>
        </div>
        <p className="pv-footer-credit">Built with ❤️ by Rolch, Maky, Cholou, Sofia &amp; the team · CMU Technopreneurship 2026</p>
        <div className="pv-footer-links">
          <button onClick={() => openAuth("login")}>Log In</button>
          <button onClick={() => openAuth("register")}>Register</button>
        </div>
      </footer>

      {/* ── AUTH MODAL ── */}
      {authModal && (
        <AuthModal initialMode={authModal} onClose={closeAuth} onAuth={handleAuthSuccess} />
      )}
    </div>
  );
}
